// Normalize the bridge's payload and derive the case fields we need
// downstream. Keeping this logic in one Code node (rather than spread
// across several Set nodes) makes the severity-tier mapping easy to find
// and edit in one place.
const item = $input.item.json;

const level = Number(item.rule_level || 0);

// TheHive severity scale: 1=low, 2=medium, 3=high, 4=critical
let severity = 2;
let tier = 'medium';
if (level >= 13) { severity = 4; tier = 'critical'; }
else if (level >= 10) { severity = 3; tier = 'high'; }
else if (level >= 7) { severity = 2; tier = 'medium'; }
else { severity = 1; tier = 'low'; }

const mitreIds = Array.isArray(item.rule_mitre_ids) ? item.rule_mitre_ids : [];
const tags = ['wazuh', 'soar-auto-case', `tier:${tier}`, `rule:${item.rule_id}`];
if (item.agent_name) tags.push(`agent:${item.agent_name}`);
mitreIds.forEach(id => tags.push(`mitre:${id}`));

const description = [
  `**Automatically created by n8n SOAR workflow**`,
  ``,
  `- Wazuh rule ID: ${item.rule_id}`,
  `- Rule level: ${level}`,
  `- Agent: ${item.agent_name || 'unknown'} (${item.agent_id || 'n/a'}, ${item.agent_ip || 'n/a'})`,
  `- Source IP: ${item.src_ip || 'n/a'}`,
  `- Destination IP: ${item.dst_ip || 'n/a'}`,
  `- MITRE ATT&CK: ${mitreIds.length ? mitreIds.join(', ') : 'n/a'}`,
  `- Timestamp: ${item.timestamp || 'n/a'}`,
  ``,
  '```',
  (item.full_log || '').slice(0, 1500),
  '```'
].join('\n');

return {
  json: {
    ...item,
    tier,
    severity,
    case_title: `[Wazuh ${tier.toUpperCase()}] ${item.rule_description || 'Unnamed alert'}`.slice(0, 200),
    case_description: description,
    case_tags: tags
  }
};

// Stand-in for a real notification (Slack/Discord/email webhook node).
// Logs to n8n's own execution log so escalations are visible in the
// Executions tab even before a notification channel is wired up.
const item = $input.item.json;
console.log(`[SOAR ESCALATION] CRITICAL Wazuh alert -> TheHive case ${item.id || '(unknown id)'}: ${item.case_title || item.title}`);
return { json: { ...item, escalation_logged: true } };
